// Get all merged items
const items = $input.all();

// Extract each type of data
const profile = items.find(i => i.json.home_station)?.json || {};
const alerts = items.filter(i => i.json.alert_type).map(i => i.json);
const journeys = items.filter(i => i.json.origin_station).map(i => i.json);
const events = items.filter(i => i.json.event_name).map(i => i.json);

// Current time
const now = new Date();

// Determine status emoji based on alerts
let statusEmoji = '✅';
let statusText = 'All clear — no issues!';

const hasDelay = alerts.some(a => a.alert_type === 'delay');
const hasWeather = alerts.some(a => a.alert_type === 'weather');
const hasClosure = alerts.some(a => a.alert_type === 'closure');
const hasEvent = events.some(e => e.expected_crowd === 'extreme' || e.expected_crowd === 'high');

if (hasClosure) {
  statusEmoji = '🚫';
  statusText = 'Line closure — check alternatives';
} else if (hasDelay && hasWeather) {
  statusEmoji = '⚠️🌧️';
  statusText = 'Delays + rain — allow extra time';
} else if (hasDelay && hasEvent) {
  statusEmoji = '⚠️🎉';
  statusText = 'Delays + busy event nearby';
} else if (hasDelay) {
  statusEmoji = '⚠️';
  statusText = 'Minor delays reported';
} else if (hasWeather) {
  statusEmoji = '🌧️';
  statusText = 'Weather alert';
} else if (hasEvent) {
  statusEmoji = '🎉';
  statusText = 'Expect crowds — event nearby';
}

return [{
  json: {
    status: {
      emoji: statusEmoji,
      text: statusText
    },
    user: {
      name: profile.name || 'Traveller',
      home_station: profile.home_station,
      work_station: profile.work_station,
      preferred_lines: profile.preferred_lines || [],
      style: profile.notification_style || 'friendly'
    },
    current_time: {
      day: now.toLocaleDateString('en-GB', { weekday: 'long' }),
      date: now.toLocaleDateString('en-GB', { day: 'numeric', month: 'long' }),
      time: now.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' })
    },
    alerts: alerts,
    journeys: journeys,
    events: events
  }
}];

